e-displayphoto-shrink_800_800/0/1627293890399?e=1778112000&v=beta&t=FgzlERdMGSQiiPgpwUxvKryy2E06v58tyJENRQ8ObdM", "peopleAlsoViewed/25/public_identifier": "jay-abiang-a6024648", "peopleAlsoViewed/25/url": "https://linkedin.com/in/ACoAAAoAimgBZr-FXlXAleKHDaJeIjOs8lDe-98", "publicIdentifier": "marcselinger", "recommendations/0/context": "Marc managed Aung Kyaw directly", "recommendations/0/date": "August 21, 2021", "recommendations/0/description": "Aung Kyaw San was part of the pre-opening team of Melia Yangon. During his time with us he greatly contributed in setting up the The Level Executive Lounge and successfully helped transform this area into a popular destination for business travellers visiting the city. As part of this duties as Butler, he was responsible to accommodate multiple requests for which he was always capable of finding the right solution, ensuring the satisfaction of our distinguished guests. He will without a doubt be a valuable asset in any future posting.", "recommendations/0/name": "Aung Kyaw San", "recommendations/0/subtitle": "Assistant Executive Butler | ASEAN National Trainer", "recommendations/0/url": "https://www.linkedin.com/in/aung-kyaw-san-770923110/", "recommendations/0/urn": "urn:li:fsd_profile:ACoAABvmpoQByHkZyka-OUWWBGkxitXyTUCZqWM", "recommendations/1/context": "Marc managed Kaung directly", "recommendations/1/date": "April 18, 2019", "recommendations/1/description": "I had the chance to work with Kaung San during the opening of Melia Yangon hotel. During this challenging period and for the following 3 years Kaung San has been an essential part of the team. Extremely valued for his  top performance and his willigness to assist other departments. It is with regret I see him go but I am sure he will perform an outstanding job wherever he goes.", "recommendations/1/name": "Kaung San", "recommendations/1/subtitle": "Reservations Services Manager", "recommendations/1/url": "https://www.linkedin.com/in/kaung-san-9793b240/", "recommendations/1/urn": "urn:li:fsd_profile:ACoAAAiZ8e0BAarIS5GFKAjoVZvoxg7Nkg45emE", "recommendationsReceived/0/context": "Oliver worked with Marc on the same team", "recommendationsReceived/0/date": "January 13, 2015", "recommendationsReceived/0/description": "Marc is a very positive and motivated person that has an incredible capacity of problem solving. He is hard worker and is always ready to help even if he is not directly involved making him a very versatile person.", "recommendationsReceived/0/name": "Oliver Rodriguez-Pearson", "recommendationsReceived/0/subtitle": "International Education Professional", "recommendationsReceived/0/url": "https://www.linkedin.com/in/oliver-rodriguez-pearson/", "recommendationsReceived/0/urn": "urn:li:fsd_profile:ACoAAAInv8YB2ooAV99oLuLQ5NSJbOqYhijDxSM", "recommendationsReceived/1/context": "Julieta managed Marc directly", "recommendationsReceived/1/date": "January 13, 2015", "recommendationsReceived/1/description": "I had the opportunity of working with Marc and being his supervisor for several years. He always demonstrated a high level of professionalism and commitment with all the tasks he has to accomplish. Marc has strong social skills and is able to work under pressure. I would absolutely recommend him for any position related to Education or Tourism. ", "recommendationsReceived/1/name": "Julieta Moya", "recommendationsReceived/1/subtitle": "Commercial Director | Business Development | EdTech | International Education Specialist | Consultant | Life Coach", "recommendationsReceived/1/url": "https://www.linkedin.com/in/julietamoya/", "recommendationsReceived/1/urn": "urn:li:fsd_profile:ACoAAAj6lc8B3OMjieO19W09DnIzjwkZPbMCWu8", "recommendationsReceived/2/context": "Nacho reported directly to Marc", "recommendationsReceived/2/date": "January 12, 2015", "recommendationsReceived/2/description": "Marc es una persona con grandes capacidades de liderazgo y gestión de equipos. \nEs destacable su capacidad de improvisación y adaptación a los diferentes entornos económicos, elaborando análisis de mercado efectivos, eficientes y a su vez desarrollando nuevas estrategias de marketing que muestran en corto plazo un aumento muy considerable de las ventas \nComo gestor de equipos su carácter de liderazgo le lleva asumir responsabilidades sin titubeos, pero con un carácter de consenso y escuchando de manera activa a sus colaboradores. \nDemuestra, también, un trato excelente y cuidadoso con sus clientes, consiguiendo así una fidelización de los mismos. Recomiendo a Marc para cualquier empresa en la que quiera desarrollar sus funciones.", "recommendationsReceived/2/name": "Nacho Travesí", "recommendationsReceived/2/subtitle": "Founder Orbio AI I Former Co-founder Cobee I Ex-Wellhub I Advisor & Investor", "recommendationsReceived/2/url": "https://www.linkedin.com/in/nacho-travesi-ai-startups/", "recommendationsReceived/2/urn": "urn:li:fsd_profile:ACoAAA4Ef9YBKpCI_GHicFptW0yEwoYe7DT3s0c", "recommendationsReceived/3/context": "Christopher worked with Marc on the same team", "recommendationsReceived/3/date": "January 9, 2015", "recommendationsReceived/3/description": "Marc was not only a very nice collegue to work with but a very professional one as well.\nMarc used to be respected by all his collegue and managers.\nHe is a very proactive and has all the soft and hard skills to be a good leader.\nI highly recommend Marc.", "recommendationsReceived/3/name": "Christopher Balestra", "recommendationsReceived/3/subtitle": "Senior HR Consultant | Federal HR Diploma", "recommendationsReceived/3/url": "https://www.linkedin.com/in/christopher-balestra/", "recommendationsReceived/3/urn": "urn:li:fsd_profile:ACoAAAljmIsBp1MBgH_XqHxQBUSZ5mSCcsTaXGU", "recommendationsReceived/4/date": "January 8, 2015", "recommendationsReceived/4/description": "I had the chance to work with Marc during my enrolment at the Ecole Hoteliere de Lausanne. He is an open minded, creative and well educated professional who is always ready to put all h